/**
 * Parse ScraperCity People Finder download response.
 * The API returns either a JSON array or an object with a 'data' or 'results' key.
 * Output: one item per person record with normalised fields.
 */
const raw = $input.first().json;

let records = [];
if (Array.isArray(raw)) {
  records = raw;
} else if (Array.isArray(raw.data)) {
  records = raw.data;
} else if (Array.isArray(raw.results)) {
  records = raw.results;
} else {
  // Wrap single object
  records = [raw];
}

return records
  .filter(r => r && (r.name || r.full_name || r.first_name))
  .map(r => ({
    json: {
      full_name: r.full_name ?? [r.first_name, r.last_name].filter(Boolean).join(' ') ?? r.name ?? '',
      email: r.email ?? r.emails?.[0] ?? '',
      phone: r.phone ?? r.phone_number ?? r.phones?.[0] ?? '',
      address: r.address ?? r.street_address ?? '',
      city: r.city ?? '',
      state: r.state ?? '',
      zip: r.zip ?? r.postal_code ?? '',
      age: r.age ?? '',
      source_run_id: $('Store Run ID').item.json.runId
    }
  }));
